/*
 * COMP 321 Project 2: Word Count
 *
 * This program counts the number of characters, words, and lines in files.
 *
 * <Put your name and NetID here>
 */

#include <ctype.h>
#include <stdarg.h>
#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

/* Structure to hold counts for a file */
struct counts {
    long chars;
    long words;
    long lines;
};

/* Function prototypes */
static int do_count(char *input_files[], const int nfiles,
    const bool char_flag, const bool word_flag,
    const bool line_flag, const bool test_flag);
static void print_counts(FILE *fp, struct counts *cnts,
    const char *name, const bool char_flag,
    const bool word_flag, const bool line_flag);
static void app_error_fmt(char *fmt, ...);

/*
 * Requires:
 *   "fp" is a valid output file stream.
 *   "cnts" is a valid pointer to a counts structure.
 *   "name" is a valid string.
 *
 * Effects:
 *   Prints the counts to fp in the format:
 *   [lines] [words] [chars] name
 *   Each count is omitted if the corresponding flag is false.
 */
static void
print_counts(FILE *fp, struct counts *cnts, const char *name,
    const bool char_flag, const bool word_flag, const bool line_flag)
{
    if (line_flag)
        fprintf(fp, "%8ld", cnts->lines);
    if (word_flag)
        fprintf(fp, "%8ld", cnts->words);
    if (char_flag)
        fprintf(fp, "%8ld", cnts->chars);
    fprintf(fp, " %s\n", name);
}

/*
 * Requires:
 *   "fmt" is a valid printf format string.
 *
 * Effects:
 *   Prints an error message to stderr in the format:
 *   ERROR: <formatted message>
 *   Does not terminate the program.
 */
__attribute__((unused))
static void
app_error_fmt(char *fmt, ...)
{
    va_list ap;
    fprintf(stderr, "ERROR: ");
    va_start(ap, fmt);
    vfprintf(stderr, fmt, ap);
    va_end(ap);
    fprintf(stderr, "\n");
}

/*
 * Requires:
 *   "input_files" is a valid array of file name strings.
 *   "nfiles" is the number of files in the array.
 *
 * Effects:
 *   Counts characters, words, and/or lines in each file based on flags.
 *   Prints results for each file in ASCIIbetical order.
 *   Prints totals at the end.
 *   Returns 0 on success, 1-255 on error.
 */
static int
do_count(char *input_files[], const int nfiles,
    const bool char_flag, const bool word_flag,
    const bool line_flag, const bool test_flag)
{
    int error_flag = 0;
    int valid_count = 0;
    struct counts total = {0, 0, 0};

    (void)test_flag;

    /* Allocate storage for valid file results. */
    struct counts *results = malloc(nfiles * sizeof(struct counts));
    char **names = malloc(nfiles * sizeof(char *));
    if (results == NULL || names == NULL) {
        free(results);
        free(names);
        print_counts(stdout, &total, "total", true, true, true);
        return 1;
    }

    /* Process each file in input order. */
    for (int i = 0; i < nfiles; i++) {
        FILE *fp;
        long chars = 0, words = 0, lines = 0;
        bool in_word = false;
        int ch;

        fp = fopen(input_files[i], "r");
        if (fp == NULL) {
            app_error_fmt("cannot open file '%s'", input_files[i]);
            error_flag = 1;
            continue;
        }

        while ((ch = fgetc(fp)) != EOF) {
            chars++;
            if (ch == '\n')
                lines++;
            if (isspace(ch)) {
                in_word = false;
            } else {
                if (!in_word) {
                    words++;
                    in_word = true;
                }
            }
        }

        if (ferror(fp)) {
            app_error_fmt("cannot read file '%s'", input_files[i]);
            error_flag = 1;
            fclose(fp);
            continue;
        }

        fclose(fp);

        results[valid_count].chars = chars;
        results[valid_count].words = words;
        results[valid_count].lines = lines;
        names[valid_count] = input_files[i];
        valid_count++;
    }

    /* Sort results by filename (ASCIIbetical order). */
    for (int i = 1; i < valid_count; i++) {
        char *key_name = names[i];
        struct counts key_cnts = results[i];
        int j = i - 1;
        while (j >= 0 && strcmp(names[j], key_name) > 0) {
            names[j + 1] = names[j];
            results[j + 1] = results[j];
            j--;
        }
        names[j + 1] = key_name;
        results[j + 1] = key_cnts;
    }

    /* Print individual results and accumulate totals. */
    for (int i = 0; i < valid_count; i++) {
        print_counts(stdout, &results[i], names[i],
            char_flag, word_flag, line_flag);
        if (char_flag)
            total.chars += results[i].chars;
        if (word_flag)
            total.words += results[i].words;
        if (line_flag)
            total.lines += results[i].lines;
    }

    /* Print totals (always print all three counts). */
    print_counts(stdout, &total, "total", true, true, true);

    free(results);
    free(names);

    return error_flag;
}

/*
 * Requires:
 *   Nothing.
 *
 * Effects:
 *   Parses command line arguments and calls do_count.
 *   Returns the value returned by do_count.
 */
int
main(int argc, char **argv)
{
    int c;
    bool char_flag = false;
    bool word_flag = false;
    bool line_flag = false;
    bool test_flag = false;

    /* Parse command line options */
    while ((c = getopt(argc, argv, "cltwh")) != -1) {
        switch (c) {
        case 'c':
            char_flag = true;
            break;
        case 'l':
            line_flag = true;
            break;
        case 't':
            test_flag = true;
            break;
        case 'w':
            word_flag = true;
            break;
        case 'h':
            printf("Usage: %s [-c] [-l] [-t] [-w] <files>\n", argv[0]);
            return 0;
        default:
            fprintf(stderr, "Usage: %s [-c] [-l] [-t] [-w] <files>\n",
                argv[0]);
            return 1;
        }
    }

    /* Check for at least one input file */
    if (optind >= argc) {
        fprintf(stderr, "Error: No input files specified\n");
        return 1;
    }

    /* Get the input files */
    int nfiles = argc - optind;
    char **input_files = &argv[optind];

    return do_count(input_files, nfiles, char_flag, word_flag,
        line_flag, test_flag);
}

"""
Agent tests for Project 2: Word Count

Additional edge case tests beyond the public test suite.
"""

import os
import sys
import tempfile
from pathlib import Path

_tests_dir = Path(__file__).parent.parent / "public"
if str(_tests_dir) not in sys.path:
    sys.path.insert(0, str(_tests_dir))

from fixtures import (
    make_test_result, run_program, compile_c_program,
    create_temp_file, cleanup_temp_path
)

TEST_POINTS = {
    "test_empty_file": 1,
    "test_single_word_no_newline": 1,
    "test_multiple_spaces_between_words": 1,
    "test_tabs_and_mixed_whitespace": 1,
