            # Should have error for nonexistent
            if "cannot open file" not in stderr:
                return make_test_result(False, "error message", stderr.strip(), None)
            # Should still have valid file counts and total
            results = _parse_output(stdout)
            fname = os.path.basename(str(f))
            actual = results.get(fname, [])
            expected = [1, 2, 12]  # lines=1, words=2, chars=12
            if actual != expected:
                return make_test_result(False, f"{fname}: {expected}", f"{fname}: {actual}", None)
            # Return code should be non-zero
            if ret == 0:
                return make_test_result(False, "non-zero return", f"return code {ret}", None)
            return make_test_result(True, "error + valid counts", stdout.strip(), None)
    except RuntimeError as e:
        return make_test_result(False, "compiled", str(e), None)


